INSERT INTO `Product` VALUES (1,'Honor Magic 2',1,'/img/phones/honor/Honor Magic 2.webp',4990000,4190000,10.00,19,12,0,'Honor Magic 2 có thiết kế trượt độc đáo, tạo cảm giác khác biệt so với nhiều mẫu máy phổ thông. Máy vẫn đáp ứng ổn các nhu cầu cơ bản như lướt web, xem video và dùng mạng xã hội.',0,1,7,1,'2026-04-11 23:32:40','2026-05-17 18:05:31'),(2,'Honor Magic 5 Pro',1,'/img/phones/honor/Honor Magic 5 Pro.webp',17990000,16490000,10.00,24,12,0,'Honor Magic 5 Pro là flagship nổi bật với camera mạnh, màn hình đẹp và hiệu năng cao. Máy phù hợp cho người dùng cần trải nghiệm cao cấp toàn diện.',0,1,7,1,'2026-04-11 23:32:40','2026-05-15 17:47:47'),(3,'Honor Magic 5',1,'/img/phones/honor/Honor Magic 5.webp',13990000,12790000,10.00,24,12,0,'Honor Magic 5 mang lại trải nghiệm cận flagship với thiết kế đẹp và hiệu năng mạnh. Máy phù hợp cho học tập, làm việc và giải trí dài lâu.',0,1,7,1,'2026-04-11 23:32:40','2026-05-07 15:00:10'),(4,'Honor Magic 6 Pro',1,'/img/phones/honor/Honor Magic 6 Pro.webp',23990000,21990000,10.00,16,12,0,'Honor Magic 6 Pro là mẫu flagship rất mạnh của Honor với camera và pin ấn tượng. Máy phù hợp cho người dùng thích công nghệ mới và hiệu năng cao.',0,1,7,1,'2026-04-11 23:32:40','2026-05-07 15:05:10'),(5,'HONOR Magic 7 Pro',1,'/img/phones/honor/HONOR Magic 7 Pro.webp',26990000,24990000,10.00,13,12,1,'HONOR Magic 7 Pro là dòng máy đời mới với thiết kế cao cấp và hiệu năng đầu bảng. Đây là lựa chọn tốt cho người dùng cần smartphone mạnh và bền lâu.',0,1,7,1,'2026-04-11 23:32:40','2026-05-13 23:24:33'),(6,'HONOR Magic V Flip 2',1,'/img/phones/honor/HONOR Magic V Flip 2.webp',23990000,22490000,10.00,12,12,0,'HONOR Magic V Flip 2 là điện thoại gập vỏ sò có thiết kế thời trang và nhỏ gọn. Máy phù hợp với người thích phong cách hiện đại và khác biệt.',0,1,7,1,'2026-04-11 23:32:40','2026-05-07 22:27:23'),(7,'Honor Magic V',1,'/img/phones/honor/Honor Magic V.webp',17990000,16490000,10.00,13,12,0,'Honor Magic V là một trong những mẫu máy gập đầu tiên của Honor với trải nghiệm màn hình lớn. Máy phù hợp cho người thích đa nhiệm và làm việc linh hoạt.',0,1,7,1,'2026-04-11 23:32:40','2026-05-07 22:31:02'),(8,'Honor Magic V2',1,'/img/phones/honor/Honor Magic V2.webp',27990000,25990000,10.00,19,12,0,'Honor Magic V2 nổi bật nhờ thiết kế mỏng nhẹ trong phân khúc điện thoại gập. Máy mang lại trải nghiệm cao cấp, màn hình đẹp và hiệu năng mạnh.',0,1,7,1,'2026-04-11 23:32:40',NULL),(9,'Honor Magic V3',1,'/img/phones/honor/Honor Magic V3.webp',35990000,33990000,10.00,13,12,0,'Honor Magic V3 là mẫu điện thoại gập cao cấp với thiết kế mỏng và cấu hình mạnh. Máy phù hợp cho người dùng thích trải nghiệm flagship mới nhất.',0,1,7,1,'2026-04-11 23:32:40',NULL),(10,'HONOR Magic V5 16GB 512GB',1,'/img/phones/honor/HONOR Magic V5 16GB 512GB.webp',39990000,37990000,10.00,8,12,1,'HONOR Magic V5 là dòng máy gập rất cao cấp với hiệu năng mạnh và bộ nhớ lớn. Máy phù hợp cho người dùng cần công nghệ mới và trải nghiệm cao cấp.',0,1,7,1,'2026-04-11 23:32:40','2026-05-20 22:04:42'),(11,'Honor Play 7T Pro',1,'/img/phones/honor/Honor Play 7T Pro.webp',4990000,4490000,10.00,26,12,0,'Honor Play 7T Pro là điện thoại phổ thông có thiết kế gọn và hiệu năng đủ dùng. Máy phù hợp cho nhu cầu học tập, giải trí và dùng hằng ngày.',0,1,7,1,'2026-04-11 23:32:40',NULL),(12,'Honor Play 7T',1,'/img/phones/honor/Honor Play 7T.webp',4490000,3990000,10.00,35,12,0,'Honor Play 7T có pin lớn và mức giá dễ tiếp cận, phù hợp cho người dùng phổ thông. Máy đáp ứng tốt các nhu cầu cơ bản như xem video, lướt web và liên lạc.',0,1,7,1,'2026-04-11 23:32:40',NULL),(13,'HONOR Play 10 4GB 128GB',1,'/img/phones/honor/HONOR Play 10 4GB 128GB.webp',3690000,3290000,10.00,30,12,0,'HONOR Play 10 là mẫu máy giá rẻ, dễ dùng và phù hợp với học sinh hoặc người dùng cơ bản. Pin tốt và giao diện đơn giản là điểm mạnh của máy.',0,1,7,1,'2026-04-11 23:32:40',NULL),(14,'Honor Play 30',1,'/img/phones/honor/Honor Play 30.webp',3290000,2890000,10.00,21,12,0,'Honor Play 30 có thiết kế đơn giản, dễ dùng và phù hợp với nhu cầu cơ bản hằng ngày. Đây là lựa chọn hợp lý trong phân khúc phổ thông.',0,1,7,1,'2026-04-11 23:32:40',NULL),(15,'Honor Play 40C',1,'/img/phones/honor/Honor Play 40C.webp',3890000,3490000,10.00,28,12,0,'Honor Play 40C là smartphone phổ thông có pin khỏe và màn hình lớn. Máy phù hợp cho người dùng cần thiết bị ổn định để dùng mỗi ngày.',0,1,7,1,'2026-04-11 23:32:40',NULL),(16,'HONOR Power 2',1,'/img/phones/honor/HONOR Power 2.webp',9990000,9190000,10.00,18,12,0,'HONOR Power 2 thiên về thời lượng pin và độ bền sử dụng lâu dài. Máy phù hợp cho người thường xuyên di chuyển hoặc cần pin trâu.',0,1,7,1,'2026-04-11 23:32:40',NULL),(17,'Honor Power',1,'/img/phones/honor/Honor Power.webp',8990000,8290000,10.00,24,12,0,'Honor Power là model tập trung vào pin khỏe và trải nghiệm ổn định. Máy phù hợp cho người dùng thích sự thực dụng và bền bỉ.',0,1,7,1,'2026-04-11 23:32:40',NULL),(18,'HONOR Win RT',1,'/img/phones/honor/HONOR Win RT.webp',5990000,5490000,10.00,13,12,0,'HONOR Win RT là mẫu máy ít phổ biến hơn, phù hợp cho nhu cầu sử dụng cơ bản. Máy có thiết kế gọn và giao diện dễ làm quen.',0,1,7,1,'2026-04-11 23:32:40',NULL),(19,'Honor X5 Plus',1,'/img/phones/honor/Honor X5 Plus.webp',2790000,2490000,10.00,34,12,0,'Honor X5 Plus là mẫu máy giá rẻ phù hợp cho người dùng phổ thông. Máy đáp ứng ổn nhu cầu nghe gọi, lướt web và giải trí nhẹ.',0,1,7,1,'2026-04-11 23:32:40',NULL),(20,'HONOR X5b 4GB 64GB',1,'/img/phones/honor/HONOR X5b 4GB 64GB.webp',2490000,2190000,10.00,36,12,0,'HONOR X5b là mẫu điện thoại giá rẻ dành cho nhu cầu sử dụng cơ bản. Máy phù hợp cho học sinh, người lớn tuổi hoặc làm máy phụ.',0,1,7,1,'2026-04-11 23:32:40',NULL),(21,'Honor X5c Plus 4GB 64GB',1,'/img/phones/honor/Honor X5c Plus 4GB 64GB.webp',2690000,2390000,10.00,22,12,0,'Honor X5c Plus 64GB là điện thoại phổ thông dễ dùng và có mức giá dễ tiếp cận. Máy phù hợp cho các nhu cầu liên lạc và học online.',0,1,7,1,'2026-04-11 23:32:40',NULL),(22,'Honor X5c Plus 4GB 128GB',1,'/img/phones/honor/Honor X5c Plus 4GB 128GB.webp',2990000,2690000,10.00,29,12,0,'Phiên bản 128GB của Honor X5c Plus cho không gian lưu trữ thoải mái hơn. Máy vẫn phù hợp với nhu cầu sử dụng hằng ngày cơ bản.',0,1,7,1,'2026-04-11 23:32:40',NULL),(23,'Honor X6',1,'/img/phones/honor/Honor X6.webp',3190000,2890000,10.00,18,12,0,'Honor X6 là điện thoại phổ thông có pin tốt và giao diện thân thiện. Máy phù hợp cho người dùng cần một thiết bị dễ dùng mỗi ngày.',0,1,7,1,'2026-04-11 23:32:40',NULL),(24,'Honor X6A',1,'/img/phones/honor/Honor X6A.webp',3690000,3290000,10.00,27,12,0,'Honor X6A là bản nâng cấp ổn định với pin tốt và màn hình mượt hơn. Máy phù hợp cho học sinh, sinh viên và người dùng phổ thông.',0,1,7,1,'2026-04-11 23:32:40',NULL),(25,'HONOR X6c 6GB 128GB',1,'/img/phones/honor/HONOR X6c 6GB 128GB.webp',4190000,3790000,10.00,23,12,0,'HONOR X6c là mẫu máy phổ thông đời mới có bộ nhớ ổn và pin tốt. Máy phù hợp cho người dùng cần thiết bị bền bỉ và dễ sử dụng.',0,1,7,1,'2026-04-11 23:32:40',NULL),(26,'Honor X7',1,'/img/phones/honor/Honor X7.webp',3990000,3590000,10.00,16,12,0,'Honor X7 có màn hình lớn và pin khỏe, phù hợp cho nhu cầu học tập và giải trí nhẹ. Máy mang lại trải nghiệm ổn định trong tầm giá.',0,1,7,1,'2026-04-11 23:32:40',NULL),(27,'Honor X7a',1,'/img/phones/honor/Honor X7a.webp',4490000,3990000,10.00,31,12,0,'Honor X7a nổi bật với pin lớn và thời lượng dùng lâu. Máy phù hợp cho người dùng cần smartphone bền bỉ, ổn định và dễ dùng.',0,1,7,1,'2026-04-11 23:32:40',NULL),(28,'HONOR X7c 8GB 256GB',1,'/img/phones/honor/HONOR X7c 8GB 256GB.webp',5990000,5490000,10.00,25,12,0,'HONOR X7c là smartphone tầm trung phổ thông với bộ nhớ lớn và hiệu năng ổn định. Máy phù hợp cho người dùng cần lưu trữ nhiều dữ liệu.',0,1,7,1,'2026-04-11 23:32:40',NULL),(29,'HONOR X7d 8GB 128GB',1,'/img/phones/honor/HONOR X7d 8GB 128GB.webp',5490000,4990000,10.00,19,12,0,'HONOR X7d 128GB cân bằng giữa hiệu năng, giá bán và dung lượng lưu trữ. Máy phù hợp cho người dùng phổ thông cần sự ổn định.',0,1,7,1,'2026-04-11 23:32:40',NULL),(30,'HONOR X7d 8GB 256GB',1,'/img/phones/honor/HONOR X7d 8GB 256GB.webp',6190000,5690000,10.00,21,12,0,'Phiên bản 256GB của HONOR X7d phù hợp với người dùng cần lưu trữ nhiều hơn. Máy đáp ứng tốt các nhu cầu sử dụng hằng ngày.',0,1,7,1,'2026-04-11 23:32:40',NULL),(31,'Honor X8 5G',1,'/img/phones/honor/Honor X8 5G.webp',4990000,4490000,10.00,24,12,0,'Honor X8 5G là mẫu máy mỏng nhẹ, đẹp mắt và có hỗ trợ kết nối 5G. Máy phù hợp cho người dùng cần thiết bị ổn định trong tầm giá.',0,1,7,1,'2026-04-11 23:32:40',NULL),(32,'Honor X8A',1,'/img/phones/honor/Honor X8A.webp',5490000,4990000,10.00,20,12,0,'Honor X8A có thiết kế đẹp, camera tốt và phù hợp với người dùng trẻ. Máy cho trải nghiệm sử dụng mượt trong các tác vụ hằng ngày.',0,1,7,1,'2026-04-11 23:32:40',NULL),(33,'HONOR X8d 8GB 128GB',1,'/img/phones/honor/HONOR X8d 8GB 128GB.webp',6290000,5790000,10.00,17,12,0,'HONOR X8d là mẫu máy tầm trung có thiết kế hiện đại và bộ nhớ tốt. Máy phù hợp cho học tập, làm việc và giải trí cơ bản.',0,1,7,1,'2026-04-11 23:32:40',NULL),(34,'Honor X9',1,'/img/phones/honor/Honor X9.webp',6290000,5790000,10.00,15,12,0,'Honor X9 nổi bật với thiết kế mỏng nhẹ và màn hình lớn. Máy phù hợp cho người dùng cần smartphone đẹp và dễ sử dụng.',0,1,7,1,'2026-04-11 23:32:40',NULL),(35,'Honor X9B',1,'/img/phones/honor/Honor X9B.webp',8990000,8190000,10.00,33,12,0,'Honor X9B là model được quan tâm nhiều nhờ pin tốt, thiết kế đẹp và độ bền cao. Máy phù hợp cho người dùng muốn dùng lâu dài.',0,1,7,1,'2026-04-11 23:32:40',NULL),(36,'HONOR X9c 5G 12GB 256GB',1,'/img/phones/honor/HONOR X9c 5G 12GB 256GB.webp',10990000,9990000,10.00,26,12,0,'HONOR X9c 5G là mẫu máy đời mới có pin mạnh và thiết kế hiện đại. Máy phù hợp cho người dùng thích smartphone đẹp, bền và hiệu năng ổn định.',0,1,7,1,'2026-04-11 23:32:40',NULL),(37,'HONOR X9d 12GB 512GB',1,'/img/phones/honor/HONOR X9d 12GB 512GB.webp',11990000,10990000,10.00,14,12,0,'HONOR X9d có bộ nhớ lớn và trải nghiệm ổn định