CREATE TABLE `ProductDetail` (
  `DetailID` int NOT NULL AUTO_INCREMENT,
  `ProductID` int NOT NULL,
  `RAM` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `Storage` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `CPU` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `Screen` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `Battery` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `Camera` varchar(200) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `OS` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `ChargingSpeed` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `Connectivity` varchar(200) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  PRIMARY KEY (`DetailID`),
  KEY `FK_ProductDetail_Product` (`ProductID`),
  CONSTRAINT `FK_ProductDetail_Product` FOREIGN KEY (`ProductID`) REFERENCES `Product` (`ProductID`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=411 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
